import { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { addVehicle } from "../../api/vehicleApi";

export default function AddVehicle() {
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState({
    brand: "",
    type: "",
    year: "",
    price: "",
    status: "available",
    vehicleNumber: "",
    details: "",
  });

  const [saving, setSaving] = useState(false);

  // ✅ images (max 4)
  const [images, setImages] = useState([]); // File[]
  const previews = useMemo(() => images.map((f) => URL.createObjectURL(f)), [images]);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const onPickImages = (e) => {
    const files = Array.from(e.target.files || []);
    const combined = [...images, ...files].slice(0, 4);
    setImages(combined);
    e.target.value = "";
  };

  const removePickedImage = (index) => {
    setImages((prev) => prev.filter((_, i) => i !== index));
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (!vehicle.brand.trim()) return alert("Brand is required");
    if (!vehicle.type) return alert("Vehicle type is required");
    if (!vehicle.year) return alert("Year is required");
    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");

    if (!vehicle.price) return alert("Price is required");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const fd = new FormData();
    fd.append("brand", vehicle.brand.trim());
    fd.append("type", vehicle.type);
    fd.append("year", String(yearNum));
    fd.append("price", String(priceNum));
    fd.append("status", vehicle.status);
    fd.append("vehicleNumber", vehicle.vehicleNumber.trim());
    fd.append("details", vehicle.details.trim());

    images.forEach((file) => fd.append("images", file));

    try {
      setSaving(true);
      await addVehicle(fd);
      alert("Vehicle added successfully");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Error adding vehicle");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 780 }}>
      <h2>Add Vehicle</h2>

      <form onSubmit={submit}>
        <label>Brand</label>
        <input
          name="brand"
          placeholder="Toyota, Honda..."
          value={vehicle.brand}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <label>Vehicle Type</label>
        <select
          name="type"
          value={vehicle.type}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        >
          <option value="">Select Vehicle Type</option>
          {vehicleTypes.map((t) => (
            <option key={t} value={t}>{t}</option>
          ))}
        </select>

        <label>Year</label>
        <input
          name="year"
          type="number"
          placeholder="2020"
          value={vehicle.year}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <label>Price (LKR)</label>
        <input
          name="price"
          type="number"
          placeholder="4500000"
          value={vehicle.price}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <label>Status</label>
        <select
          name="status"
          value={vehicle.status}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        >
          {statuses.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>

        <label>Vehicle Number (optional)</label>
        <input
          name="vehicleNumber"
          placeholder="e.g., ABC-1234"
          value={vehicle.vehicleNumber}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        />

        <label>Details (optional)</label>
        <textarea
          name="details"
          placeholder="Any extra notes..."
          value={vehicle.details}
          onChange={handleChange}
          rows={3}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        />

        {/* ✅ Photos */}
        <label>Vehicle Photos (max 4)</label>
        <input
          type="file"
          accept="image/*"
          multiple
          onChange={onPickImages}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        />

        {previews.length > 0 && (
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 10 }}>
            {previews.map((src, idx) => (
              <div key={src} style={{ border: "1px solid #ddd", borderRadius: 12, padding: 10 }}>
                <div style={{ width: 220, aspectRatio: "4 / 3", overflow: "hidden", borderRadius: 10 }}>
                  <img src={src} alt="preview" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                </div>
                <button type="button" onClick={() => removePickedImage(idx)} style={{ marginTop: 8 }}>
                  Remove
                </button>
              </div>
            ))}
          </div>
        )}

        <button disabled={saving} style={{ padding: "10px 14px" }}>
          {saving ? "Saving..." : "Save"}
        </button>
      </form>
    </div>
  );
}
